const items = $input.all();
if (items.length === 1 && Array.isArray(items[0].json)) {
  return items[0].json.map(l => ({ json: l }));
}
if (items.length === 1 && items[0].json && Array.isArray(items[0].json.data)) {
  return items[0].json.data.map(l => ({ json: l }));
}
return items;

const a = $input.first().json;                 // audit result
const lead = $('Split leads').item.json;       // current lead context

const measured = (a.issues || []).map(i => ({
  label: i.label, severity: i.severity, evidence: i.evidence, fix: i.recommendation
}));

const prompt = [
  "You are auditing a business website for SNC, a web & automation agency.",
  "You are given TWO inputs:",
  "1) MEASURED ISSUES: a JSON list of problems already verified by an automated audit. These are FACTS.",
  "2) Two screenshots (desktop, mobile) of the SAME page, with cookie banners already removed.",
  "",
  "Your job:",
  "- Treat MEASURED ISSUES as the source of truth. Never contradict or re-measure them.",
  "- Inspect the screenshots ONLY for things measurements can't capture: visual design quality,",
  "  clarity of the value proposition, trust signals, clutter, dated look, confusing layout, weak hero/headline.",
  "",
  "HARD RULES:",
  "- NEVER mention cookie banners, popups, or consent dialogs.",
  "- NEVER invent technical / SEO / mobile claims that are not in MEASURED ISSUES.",
  "- A visual point must be clearly visible in the screenshot. If unsure, leave it out.",
  "- Every point must tie to lost customers, in plain language a business owner understands. No jargon.",
  "",
  "Return JSON ONLY in this exact shape:",
  '{ "score": <0-100>, "top_issues": [ { "issue": "...", "why_it_matters": "...", "source": "measured" | "visual" } ], "design_notes": ["..."], "email_angle": "one plain-language sentence hook for a cold email" }',
  "- top_issues: max 4, ranked by impact.",
  "",
  "MEASURED ISSUES: " + JSON.stringify(measured),
  "LEAD: " + (lead.business_name || "") + " | " + (lead.niche || "") + " in " + (lead.location || "")
].join("\n");

const parts = [{ text: prompt }];
const b = a.screenshots_b64 || {};
if (b.desktop) parts.push({ inlineData: { mimeType: "image/png", data: b.desktop } });
if (b.mobile)  parts.push({ inlineData: { mimeType: "image/png", data: b.mobile } });

const geminiBody = {
  contents: [{ role: "user", parts }],
  generationConfig: { temperature: 0.2, responseMimeType: "application/json" }
};

return [{ json: {
  id: a.id || lead.id,
  business_name: lead.business_name,
  niche: lead.niche,
  location: lead.location,
  measured_score: (a.scores && a.scores.overall) != null ? a.scores.overall : null,
  screenshot_url: (a.screenshots && a.screenshots.desktop) || "",
  geminiBody
}}];

const g = $input.first().json;
let txt = "";
try { txt = (g.candidates[0].content.parts || []).map(p => p.text || "").join(""); } catch (e) {}
let parsed = {};
try { parsed = JSON.parse(txt.replace(/```json|```/g, "").trim()); } catch (e) { parsed = {}; }

const src = $('Build Gemini').item.json;
const patchBody = {
  audit_score: (parsed.score != null ? parsed.score : src.measured_score),
  audit_issues: parsed.top_issues || [],
  audit_notes: parsed.design_notes || [],
  audit_email_angle: parsed.email_angle || "",
  audit_screenshot: src.screenshot_url || "",
  status: "audited"
};
return [{ json: { id: src.id, patchBody } }];
